package com.southsouthwest.framelog.ui.widget

import android.content.Context
import android.os.VibrationEffect
import android.os.Vibrator
import androidx.datastore.preferences.core.Preferences
import androidx.glance.GlanceId
import androidx.glance.appwidget.action.ActionCallback
import androidx.glance.appwidget.state.getAppWidgetState
import androidx.glance.appwidget.state.updateAppWidgetState
import androidx.glance.action.ActionParameters
import androidx.glance.state.PreferencesGlanceStateDefinition
import com.southsouthwest.framelog.data.db.AppDatabase
import com.southsouthwest.framelog.data.db.entity.Frame
import com.southsouthwest.framelog.data.db.entity.FrameFilter
import com.southsouthwest.framelog.data.repository.FrameRepository
import kotlinx.coroutines.flow.first

// ---------------------------------------------------------------------------
// Stepper direction helpers
// ---------------------------------------------------------------------------

/**
 * Steps to the next value in [list] relative to [current], clamped at the boundaries.
 *
 * Both aperture and shutter lists are ordered "more exposure → less exposure":
 *   Aperture: widest first (f/1.4 … f/22)
 *   Shutter:  slowest first (B … 1/8000)
 *
 * "Up" (more exposure) = lower index  — wider aperture or slower shutter.
 * "Down" (less exposure) = higher index — narrower aperture or faster shutter.
 *
 * If [current] isn't in the list (e.g. stale state after roll change), snap to the midpoint.
 */
private fun stepUp(list: List<String>, current: String): String {
    if (list.isEmpty()) return current
    val idx = list.indexOf(current)
    val safeIdx = if (idx == -1) list.size / 2 else idx
    return list[(safeIdx - 1).coerceAtLeast(0)]
}

private fun stepDown(list: List<String>, current: String): String {
    if (list.isEmpty()) return current
    val idx = list.indexOf(current)
    val safeIdx = if (idx == -1) list.size / 2 else idx
    return list[(safeIdx + 1).coerceAtMost(list.size - 1)]
}

private fun parseList(raw: String): List<String> =
    raw.split(",").filter { it.isNotBlank() }

// ---------------------------------------------------------------------------
// Aperture stepper actions
// ---------------------------------------------------------------------------

/**
 * Increments aperture — moves to a wider aperture (lower f-number = lower index in list).
 * Reads current aperture and list from GlanceState, writes the new value, re-renders.
 */
class ApertureUpAction : ActionCallback {
    override suspend fun onAction(
        context: Context,
        glanceId: GlanceId,
        parameters: ActionParameters,
    ) {
        vibrateIncrement(context)
        updateAppWidgetState(context, glanceId) { prefs ->
            val list = parseList(prefs[WidgetState.APERTURE_LIST] ?: "")
            val current = prefs[WidgetState.APERTURE] ?: ""
            prefs[WidgetState.APERTURE] = stepUp(list, current)
        }
        FrameLogWidget().update(context, glanceId)
    }
}

/**
 * Decrements aperture — moves to a narrower aperture (higher f-number = higher index in list).
 */
class ApertureDownAction : ActionCallback {
    override suspend fun onAction(
        context: Context,
        glanceId: GlanceId,
        parameters: ActionParameters,
    ) {
        vibrateDecrement(context)
        updateAppWidgetState(context, glanceId) { prefs ->
            val list = parseList(prefs[WidgetState.APERTURE_LIST] ?: "")
            val current = prefs[WidgetState.APERTURE] ?: ""
            prefs[WidgetState.APERTURE] = stepDown(list, current)
        }
        FrameLogWidget().update(context, glanceId)
    }
}

// ---------------------------------------------------------------------------
// Shutter speed stepper actions
// ---------------------------------------------------------------------------

/**
 * Increments shutter — moves to a slower speed (more exposure = lower index in list).
 * Long-exposure values (B, whole seconds) render in the accent color automatically.
 */
class ShutterUpAction : ActionCallback {
    override suspend fun onAction(
        context: Context,
        glanceId: GlanceId,
        parameters: ActionParameters,
    ) {
        vibrateIncrement(context)
        updateAppWidgetState(context, glanceId) { prefs ->
            val list = parseList(prefs[WidgetState.SHUTTER_LIST] ?: "")
            val current = prefs[WidgetState.SHUTTER] ?: ""
            prefs[WidgetState.SHUTTER] = stepUp(list, current)
        }
        FrameLogWidget().update(context, glanceId)
    }
}

/**
 * Decrements shutter — moves to a faster speed (less exposure = higher index in list).
 */
class ShutterDownAction : ActionCallback {
    override suspend fun onAction(
        context: Context,
        glanceId: GlanceId,
        parameters: ActionParameters,
    ) {
        vibrateDecrement(context)
        updateAppWidgetState(context, glanceId) { prefs ->
            val list = parseList(prefs[WidgetState.SHUTTER_LIST] ?: "")
            val current = prefs[WidgetState.SHUTTER] ?: ""
            prefs[WidgetState.SHUTTER] = stepDown(list, current)
        }
        FrameLogWidget().update(context, glanceId)
    }
}

// ---------------------------------------------------------------------------
// Log Frame action
// ---------------------------------------------------------------------------

/**
 * Logs the current frame to Room using the aperture and shutter shown on the widget.
 *
 * Widget limitations vs Quick Screen:
 *   - No confirmation dialog for overwrite — silently overwrites a previously logged frame.
 *     (Widgets cannot show dialogs. The user can correct via the Frame Detail screen.)
 *   - No GPS capture — widgets cannot request location permission.
 *   - No filter changes — the widget does not manage active filter state. FrameFilter rows
 *     for the target frame are left unchanged (empty for a fresh slot).
 *   - Haptic feedback uses direct Vibrator.vibrate() (VIBRATE permission required).
 *     The accessibility-aware LocalHapticFeedback path is unavailable outside Compose.
 *
 * After a successful write, the frame pointer advances to the next unlogged frame in
 * SharedPreferences, and FrameLogWidgetUpdater.update() fully refreshes the widget.
 */
class LogFrameAction : ActionCallback {
    override suspend fun onAction(
        context: Context,
        glanceId: GlanceId,
        parameters: ActionParameters,
    ) {
        // Read the current widget state from GlanceState (DataStore).
        // getAppWidgetState requires an explicit GlanceStateDefinition — no 2-arg convenience exists.
        val state: Preferences = getAppWidgetState(context, PreferencesGlanceStateDefinition, glanceId)
        val rollId = state[WidgetState.ROLL_ID] ?: return
        val frameNumber = state[WidgetState.FRAME_NUMBER] ?: return
        val aperture = state[WidgetState.APERTURE]
        val shutter = state[WidgetState.SHUTTER]
        val lensId: Int? = state[WidgetState.LENS_ID]?.takeIf { it != -1 }
        val targetFilterIds: Set<Int> = parseList(state[WidgetState.FILTER_IDS] ?: "")
            .map { it.toInt() }.toSet()

        val db = AppDatabase.getInstance(context)
        val frameRepository = FrameRepository(db)

        // Load the roll to find the target frame entity by frameNumber
        val rollWithDetails = db.rollDao().getRollById(rollId).first() ?: return
        val frame = rollWithDetails.frames.firstOrNull { it.frameNumber == frameNumber } ?: return

        // Build the updated frame.
        // GPS is null — the widget cannot request location permission.
        // lensId, exposureCompensation, and notes are retained from the existing frame slot
        // (set during the previous Quick Screen session or left at their defaults).
        val updatedFrame = Frame(
            id = frame.id,
            rollId = frame.rollId,
            frameNumber = frame.frameNumber,
            isLogged = true,
            loggedAt = System.currentTimeMillis(),
            aperture = aperture,
            shutterSpeed = shutter,
            lensId = lensId,
            exposureCompensation = frame.exposureCompensation,
            lat = null,
            lng = null,
            notes = frame.notes,
        )

        // Compute filter delta relative to what is already on the frame slot.
        // For a fresh (unlogged) frame this is always emptySet, but we read it defensively
        // in case the user previously logged and then the widget is re-logging the same slot.
        val previousFilterIds = db.frameDao().getFrameById(frame.id).first()
            .filters.map { it.id }.toSet()
        val filtersToAdd = (targetFilterIds - previousFilterIds).map { filterId ->
            FrameFilter(frameId = frame.id, filterId = filterId)
        }
        val filterIdsToRemove = (previousFilterIds - targetFilterIds).toList()

        frameRepository.logFrame(updatedFrame, filtersToAdd, filterIdsToRemove)
        vibrateConfirm(context)

        // Full widget refresh — re-derives the frame pointer from Room (first unlogged frame
        // after the highest logged frame number, or roll complete state).
        FrameLogWidgetUpdater.update(context)
    }
}

package com.southsouthwest.framelog.ui.gear

import android.app.Application
import androidx.lifecycle.AndroidViewModel
import androidx.lifecycle.SavedStateHandle
import androidx.lifecycle.viewModelScope
import com.southsouthwest.framelog.data.db.AppDatabase
import com.southsouthwest.framelog.data.db.entity.ApertureIncrements
import com.southsouthwest.framelog.data.db.entity.Lens
import com.southsouthwest.framelog.data.repository.GearRepository
import kotlinx.coroutines.channels.Channel
import kotlinx.coroutines.flow.Flow
import kotlinx.coroutines.flow.MutableStateFlow
import kotlinx.coroutines.flow.StateFlow
import kotlinx.coroutines.flow.asStateFlow
import kotlinx.coroutines.flow.receiveAsFlow
import kotlinx.coroutines.flow.update
import kotlinx.coroutines.launch

// ---------------------------------------------------------------------------
// UiState
// ---------------------------------------------------------------------------

/**
 * Editable form state for the Lens Detail/Edit screen.
 *
 * When [id] == 0 this is a new lens (Create mode). Non-zero means Edit mode.
 * [isDirty] gates the unsaved-changes back-press prompt.
 */
data class LensDetailUiState(
    val id: Int = 0,
    val name: String = "",
    val make: String = "",
    val focalLengthMm: String = "", // String for the text field; validated on save
    val mountType: String = "",
    val maxAperture: String = "", // "f/" prefix stripped in the input field
    val minAperture: String = "",
    val apertureIncrements: ApertureIncrements = ApertureIncrements.THIRD,
    val filterSizeMm: String = "", // blank = null in DB
    val notes: String = "",
    // Autocomplete suggestions for the folksonomy mount type field
    val mountTypeSuggestions: List<String> = emptyList(),
    val isLoading: Boolean = false,
    val isSaving: Boolean = false,
    val isDirty: Boolean = false,
    // Inline validation errors — null means valid
    val nameError: String? = null,
    val makeError: String? = null,
    val focalLengthError: String? = null,
    val mountTypeError: String? = null,
    val maxApertureError: String? = null,
    val minApertureError: String? = null,
)

// ---------------------------------------------------------------------------
// Events
// ---------------------------------------------------------------------------

sealed class LensDetailEvent {
    data object SaveSuccessful : LensDetailEvent()
    data object DeleteSuccessful : LensDetailEvent()
    /** User pressed back with unsaved changes — prompt them before discarding. */
    data object ConfirmDiscard : LensDetailEvent()
}

// ---------------------------------------------------------------------------
// ViewModel
// ---------------------------------------------------------------------------

class LensDetailViewModel(
    application: Application,
    savedState: SavedStateHandle,
) : AndroidViewModel(application) {

    /** 0 = new lens, non-zero = edit existing lens. Passed via nav arg key "id". */
    private val lensId: Int = savedState["id"] ?: 0

    private val gearRepository = GearRepository(AppDatabase.getInstance(application))

    private val _state = MutableStateFlow(LensDetailUiState(id = lensId, isLoading = lensId != 0))
    val state: StateFlow<LensDetailUiState> = _state.asStateFlow()

    private val _events = Channel<LensDetailEvent>(Channel.BUFFERED)
    val events: Flow<LensDetailEvent> = _events.receiveAsFlow()

    init {
        loadMountTypeSuggestions()
        if (lensId != 0) loadExistingLens()
    }

    private fun loadMountTypeSuggestions() = viewModelScope.launch {
        gearRepository.getDistinctMountTypes().collect { types ->
            _state.update { it.copy(mountTypeSuggestions = types) }
        }
    }

    private fun loadExistingLens() = viewModelScope.launch {
        // take(1): populate form once from DB, then leave it editable without
        // subsequent DB updates overwriting the user's in-progress edits.
        gearRepository.getLensById(lensId).collect { lens ->
            _state.update {
                it.copy(
                    name = lens.name,
                    make = lens.make,
                    focalLengthMm = lens.focalLengthMm.toString(),
                    mountType = lens.mountType,
                    maxAperture = lens.maxAperture.toString(),
                    minAperture = lens.minAperture.toString(),
                    apertureIncrements = lens.apertureIncrements,
                    filterSizeMm = lens.filterSizeMm?.toString() ?: "",
                    notes = lens.notes ?: "",
                    isLoading = false,
                    isDirty = false,
                )
            }
            // Stop collecting after the first value
            return@collect
        }
    }

    // ---------------------------------------------------------------------------
    // Field updates — each marks the form dirty
    // ---------------------------------------------------------------------------

    fun onNameChanged(value: String) =
        _state.update { it.copy(name = value, isDirty = true, nameError = null) }

    fun onMakeChanged(value: String) =
        _state.update { it.copy(make = value, isDirty = true, makeError = null) }

    fun onFocalLengthChanged(value: String) =
        _state.update { it.copy(focalLengthMm = value, isDirty = true, focalLengthError = null) }

    fun onMountTypeChanged(value: String) =
        _state.update { it.copy(mountType = value, isDirty = true, mountTypeError = null) }

    fun onMaxApertureChanged(value: String) =
        _state.update { it.copy(maxAperture = value, isDirty = true, maxApertureError = null) }

    fun onMinApertureChanged(value: String) =
        _state.update { it.copy(minAperture = value, isDirty = true, minApertureError = null) }

    fun onApertureIncrementsChanged(value: ApertureIncrements) =
        _state.update { it.copy(apertureIncrements = value, isDirty = true) }

    fun onFilterSizeChanged(value: String) =
        _state.update { it.copy(filterSizeMm = value, isDirty = true) }

    fun onNotesChanged(value: String) =
        _state.update { it.copy(notes = value, isDirty = true) }

    // ---------------------------------------------------------------------------
    // Save
    // ---------------------------------------------------------------------------

    fun onSaveTapped() = viewModelScope.launch {
        val s = _state.value
        if (!validate(s)) return@launch

        _state.update { it.copy(isSaving = true) }

        val lens = Lens(
            id = lensId,
            name = s.name.trim(),
            make = s.make.trim(),
            focalLengthMm = s.focalLengthMm.toInt(),
            mountType = s.mountType.trim(),
            maxAperture = s.maxAperture.toFloat(),
            minAperture = s.minAperture.toFloat(),
            apertureIncrements = s.apertureIncrements,
            filterSizeMm = s.filterSizeMm.toIntOrNull(),
            notes = s.notes.trim().ifBlank { null },
        )

        if (lensId == 0) {
            gearRepository.insertLens(lens)
        } else {
            gearRepository.updateLens(lens)
        }

        _state.update { it.copy(isSaving = false, isDirty = false) }
        _events.send(LensDetailEvent.SaveSuccessful)
    }

    // ---------------------------------------------------------------------------
    // Delete
    // ---------------------------------------------------------------------------

    fun onDeleteConfirmed() = viewModelScope.launch {
        val s = _state.value
        if (lensId == 0) return@launch // shouldn't happen — delete only shown in edit mode
        val lens = Lens(
            id = lensId,
            name = s.name,
            make = s.make,
            focalLengthMm = s.focalLengthMm.toIntOrNull() ?: 0,
            mountType = s.mountType,
            maxAperture = s.maxAperture.toFloatOrNull() ?: 0f,
            minAperture = s.minAperture.toFloatOrNull() ?: 0f,
            apertureIncrements = s.apertureIncrements,
        )
        gearRepository.deleteLens(lens)
        _events.send(LensDetailEvent.DeleteSuccessful)
    }

    // ---------------------------------------------------------------------------
    // Back press
    // ---------------------------------------------------------------------------

    fun onBackPressed() = viewModelScope.launch {
        if (_state.value.isDirty) {
            _events.send(LensDetailEvent.ConfirmDiscard)
        }
        // If not dirty, the UI navigates back directly without asking the ViewModel.
    }

    // ---------------------------------------------------------------------------
    // Validation
    // ---------------------------------------------------------------------------

    private fun validate(s: LensDetailUiState): Boolean {
        var valid = true

        if (s.name.isBlank()) {
            _state.update { it.copy(nameError = "Name is required") }
            valid = false
        }
        if (s.make.isBlank()) {
            _state.update { it.copy(makeError = "Make is required") }
            valid = false
        }
        if (s.focalLengthMm.toIntOrNull() == null || s.focalLengthMm.toInt() <= 0) {
            _state.update { it.copy(focalLengthError = "Enter a valid focal length in mm") }
            valid = false
        }
        if (s.mountType.isBlank()) {
            _state.update { it.copy(mountTypeError = "Mount type is required") }
            valid = false
        }
        val maxAp = s.maxAperture.toFloatOrNull()
        if (maxAp == null || maxAp <= 0f) {
            _state.update { it.copy(maxApertureError = "Enter a valid maximum aperture") }
            valid = false
        }
        val minAp = s.minAperture.toFloatOrNull()
        if (minAp == null || minAp <= 0f) {
            _state.update { it.copy(minApertureError = "Enter a valid minimum aperture") }
            valid = false
        }
        if (maxAp != null && minAp != null && maxAp > minAp) {
            _state.update { it.copy(maxApertureError = "Max aperture must be ≤ min aperture (wider = smaller f-number)") }
            valid = false
        }
        return valid
    }
}

