            val loggedCount = roll.frames.count { it.isLogged }
            val totalCount = roll.frames.size
            val lastLoggedAt = roll.frames
                .filter { it.isLogged }
                .maxByOrNull { it.loggedAt ?: 0L }
                ?.loggedAt

            Row(
                modifier = Modifier
