/**
 * Returns the device vibrator.
 *
 * On API 31+ (Android 12) the Vibrator system service is accessed through VibratorManager.
 * Glance ActionCallback contexts don't reliably route Context.getSystemService(Vibrator) on
 * these API levels, so we use VibratorManager.defaultVibrator explicitly.
 * On API 26–30 the direct Vibrator path is used.
 */
@Suppress("DEPRECATION")
private fun getVibrator(context: Context): Vibrator? =
    if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.S) {
        context.applicationContext.getSystemService(VibratorManager::class.java)?.defaultVibrator
    } else {
        context.applicationContext.getSystemService(Vibrator::class.java)?.takeIf { it.hasVibrator() }
    }

/** Single firm pulse — stepper increment (+).
 *  Uses createWaveform: on some devices createOneShot is silently suppressed. */
private fun vibrateIncrement(context: Context) {
    getVibrator(context)?.vibrate(VibrationEffect.createWaveform(longArrayOf(0, 80), intArrayOf(0, 255), -1))
}

