        context.applicationContext.getSystemService(VibratorManager::class.java)?.defaultVibrator
    } else {
        context.applicationContext.getSystemService(Vibrator::class.java)?.takeIf { it.hasVibrator() }
    }

/** Single firm pulse — stepper increment (+).
 *  Uses createWaveform: on some devices createOneShot is silently suppressed. */
private fun vibrateIncrement(context: Context) {
    getVibrator(context)?.vibrate(VibrationEffect.createWaveform(longArrayOf(0, 80), intArrayOf(0, 255), -1))
}

/** Double short pulse — stepper decrement (−). */
private fun vibrateDecrement(context: Context) {
    getVibrator(context)?.vibrate(VibrationEffect.createWaveform(longArrayOf(0, 30, 50, 30), intArrayOf(0, 80, 0, 80), -1))
}

/** Longer firm pulse — successful frame log confirmation. */
private fun vibrateConfirm(context: Context) {
    getVibrator(context)?.vibrate(VibrationEffect.createWaveform(longArrayOf(0, 200), intArrayOf(0, 255), -1))
}

